  id: number;
  title: string;
  content: string;
  createdAt: Date;
}

const postsStore: Post[] = [];

export async function getPosts(): Promise<Post[]> {
  // Return a copy to prevent mutation
  return [...postsStore];
}

export async function createPost(data: {
  title: string;
  content: string;
}): Promise<Post> {
  const post: Post = {
    id: postsStore.length + 1,
    title: data.title,
    content: data.content,
    createdAt: new Date(),
  };
  postsStore.push(post);
  return post;
}
