{"file_path":"/home/user/workspace/app/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { createPost } from '@/app/lib/data';

export interface ActionResult {
  error?: string;
  success?: boolean;
}

export async function createPostAction(
  _prevState: ActionResult | null,
  formData: FormData
): Promise<ActionResult> {
  const title = formData.get('title') as string | null;
  const content = formData.get('content') as string | null;

  if (!title?.trim()) {
    return { error: 'Title is required.' };
  }
  if (!content?.trim()) {
    return { error: 'Content is required.' };
  }

  await createPost({ title: title.trim(), content: content.trim() });

  // Invalidate the "posts" cache tag so the next fetch with this tag
  // waits for fresh data instead of serving stale cached content.
  revalidateTag('posts');

  return { success: true };
}
"}

{"file_path":"/home/user/workspace/app/post-form.tsx","content":"'use client';

import { useActionState } from 'react';
import { createPostAction } from '@/app/actions';

export default function PostForm() {
  const [state, formAction, pending] = useActionState(createPostAction, null);

  return (
    <form action={formAction} style={{ marginBottom: '2rem' }}>
      <div>
        <input
          name="title"
          type="text"
          placeholder="Post title"
          required
          disabled={pending}
          style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem' }}
        />
      </div>
      <div>
        <textarea
          name="content"
          placeholder="Post content"
          required
          rows={4}
          disabled={pending}
          style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem' }}
        />
      </div>
      <button type="submit" disabled={pending}>
        {pending ? 'Creating...' : 'Create Post'}
      </button>
      {state?.error && (
        <p style={{ color: '#d32f2f', marginTop: '0.5rem' }}>{state.error}</p>
      )}
      {state?.success && !pending && (
        <p style={{ color: '#2e7d32', marginTop: '0.5rem' }}>
          Post created! The page has been refreshed with fresh data.
        </p>
      )}
    </form>
  );
}
"}

{"file_path":"/home/user/workspace/app/page.tsx","content":"import PostForm from '@/app/post-form';

export const dynamic = 'force-dynamic';

export default async function Home() {
  const baseUrl = process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000';
  const res = await fetch(`${baseUrl}/api/posts`, {
    next: { tags: ['posts'] },
  });
  const posts: Array<{
    id: number;
    title: string;
    content: string;
    createdAt: string;
  }> = await res.json();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1>Posts</h1>
      <PostForm />
      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {posts.map((post) => (
            <li
              key={post.id}
              style={{
                border: '1px solid #ddd',
                borderRadius: 6,
                padding: '1rem',
                marginBottom: '0.75rem',
              }}
            >
              <h2 style={{ margin: '0 0 0.5rem' }}>{post.title}</h2>
              <p style={{ margin: 0 }}>{post.content}</p>
              <small style={{ color: '#666' }}>
                {new Date(post.createdAt).toLocaleString()}
              </small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}
"}

